class Solution {
public:
    int minimumScore(string s, string t) {
        int m = s.size(), n = t.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s[i - 1] == t[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }

        int maxMatch = dp[m][n];
        if (maxMatch == n) return 0;

        int res = n;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int left = i, right = j;
                int match = 0;
                int p = 0;
                for (int k = 0; k < m; k++) {
                    if (p < n && s[k] == t[p]) {
                        p++;
                        match++;
                    }
                }
                if (match == n - (right - left + 1)) {
                    res = min(res, right - left + 1);
                }
            }
        }

        return res;
    }
};

